// Dead-man-switch: find the freshest perception_tick + weekly_brief and
// decide whether the worker has gone silent. Thresholds chosen vs the 6h
// perception cron + weekly brief cadence, with buffer.
const rows = $input.first().json || [];
const arr = Array.isArray(rows) ? rows : [];
const now = Date.now();

function latestMs(kind) {
  const ts = arr
    .filter((r) => r.kind === kind && r.start_time)
    .map((r) => new Date(r.start_time).getTime())
    .filter((t) => !Number.isNaN(t))
    .sort((a, b) => b - a);
  return ts.length ? ts[0] : null;
}

const TICK_MAX_H = 8;
const BRIEF_MAX_D = 8;
const tick = latestMs('perception_tick');
// OPS-2 fix: the weekly producer (workflows/weekly_brief.json) writes kind
// 'weekly_brief_trigger', not 'weekly_brief' — the old filter never matched,
// so brief was always null and the monitor paged a permanent false positive.
const brief = latestMs('weekly_brief_trigger');
const tickAgeH = tick === null ? null : (now - tick) / 3.6e6;
const briefAgeD = brief === null ? null : (now - brief) / 8.64e7;

const problems = [];
if (tick === null) problems.push('perception_tick: \u10d0\u10e0\u10d0\u10e1\u10d3\u10d4\u10e1 (\u10d0\u10e0\u10d0\u10e1\u10dd\u10d3\u10d4\u10e1)');
else if (tickAgeH > TICK_MAX_H) problems.push('perception_tick: ' + tickAgeH.toFixed(1) + '\u10e1\u10d7 \u10ec\u10d8\u10dc (> ' + TICK_MAX_H + '\u10e1\u10d7)');
if (brief === null) problems.push('weekly_brief: \u10d0\u10e0\u10d0\u10e1\u10d3\u10d4\u10e1');
else if (briefAgeD > BRIEF_MAX_D) problems.push('weekly_brief: ' + briefAgeD.toFixed(1) + ' \u10d3\u10e6\u10d4 \u10ec\u10d8\u10dc (> ' + BRIEF_MAX_D + ')');

const stale = problems.length > 0;
const text = stale
  ? '\u26A0\uFE0F ALEKSANDRA_BRAIN \u2014 worker \u10d2\u10d0\u10e9\u10e3\u10db\u10d3\u10d0\n' + problems.join('\n')
  : '';
const auditReason =
  'tick=' + (tickAgeH === null ? 'none' : tickAgeH.toFixed(1) + 'h') +
  ' brief=' + (briefAgeD === null ? 'none' : briefAgeD.toFixed(1) + 'd') +
  ' stale=' + stale;
return [{ json: { stale, text, auditReason, summary: { tick_age_h: tickAgeH, brief_age_d: briefAgeD, problems, stale } } }];

// Gate: only let the Telegram alert fire when stale. Returning [] when
// healthy stops the downstream Telegram node from executing — no spam.
const j = $input.first().json;
return j.stale ? [{ json: j }] : [];
